DECLARE
  p_id uuid;
BEGIN
  SELECT id INTO p_id FROM projects WHERE is_active = true ORDER BY created_at LIMIT 1;
  IF p_id IS NULL THEN
    RAISE EXCEPTION 'No active project found.';
  END IF;
  DELETE FROM sites WHERE project_id = p_id AND smartsheet_row_id IS NULL;
